162	// RunCompareViaService is the production replacement for Runner.RunCompare.
163	// It resolves prompts from inline text or PromptFile and drives each arm
164	// through the agent service (RunViaService).
165	func RunCompareViaService(ctx context.Context, workDir string, opts CompareOptions) (*ComparisonRecord, error) {
166		run := func(runOpts RunOptions) (*Result, error) {
167			return RunViaService(ctx, workDir, runOpts)
168		}
169		return RunCompareWith(run, opts, defaultResolvePromptForCompare, cleanupCompareWorktrees)
170	}
