172	// RunCompareWithAgent calls RunCompareViaService using a pre-built DdxAgent.
173	// Suitable for callers that want to reuse a service instance.
174	func RunCompareWithAgent(ctx context.Context, agent agentlib.DdxAgent, workDir string, opts CompareOptions) (*ComparisonRecord, error) {
175		run := func(runOpts RunOptions) (*Result, error) {
176			return RunViaServiceWith(ctx, agent, workDir, runOpts)
177		}
178		return RunCompareWith(run, opts, defaultResolvePromptForCompare, cleanupCompareWorktrees)
179	}
