255	func createCompareWorktree(workDir, compareID, harnessName string) (string, error) {
256		gitRoot, err := resolveGitRoot(workDir)
257		if err != nil {
258			return "", fmt.Errorf("resolving git root: %w", err)
259		}
260		wtDir := filepath.Join(gitRoot, ".worktrees", fmt.Sprintf("%s-%s", compareID, harnessName))
261		cmd := internalgit.Command(context.Background(), gitRoot, "worktree", "add", "--detach", wtDir, "HEAD")
262		if out, err := cmd.CombinedOutput(); err != nil {
263			return "", fmt.Errorf("git worktree add: %s\n%s", err, string(out))
264		}
265		return wtDir, nil
266	}
267	
268	func resolveGitRoot(dir string) (string, error) {
269		cmd := internalgit.Command(context.Background(), dir, "rev-parse", "--show-toplevel")
270		out, err := cmd.Output()
271		if err != nil {
272			return "", fmt.Errorf("not a git repository: %s", dir)
273		}
274		return strings.TrimSpace(string(out)), nil
275	}
276	
277	func captureGitDiff(worktreePath string) string {
278		cmd := internalgit.Command(context.Background(), worktreePath, "diff", "HEAD")
279		out, err := cmd.Output()
280		if err != nil {
281			return ""
282		}
283		diff := string(out)
284	
285		cmd3 := internalgit.Command(context.Background(), worktreePath, "ls-files", "--others", "--exclude-standard")
286		untrackedOut, _ := cmd3.Output()
287		untracked := strings.TrimSpace(string(untrackedOut))
288		if untracked != "" {
289			for _, f := range strings.Split(untracked, "\n") {
290				f = strings.TrimSpace(f)
291				if f == "" {
292					continue
293				}
294				content, err := os.ReadFile(filepath.Join(worktreePath, f))
295				if err != nil {
296					continue
297				}
298				diff += fmt.Sprintf("\n--- /dev/null\n+++ b/%s\n@@ -0,0 +1 @@\n", f)
299				for _, line := range strings.Split(string(content), "\n") {
300					if line != "" || len(content) > 0 {
301						diff += "+" + line + "\n"
302					}
303				}
304			}
305		}
306		return strings.TrimSpace(diff)
307	}
