428	// CondenseOutput filters raw agent output to keep only progress-relevant lines.
429	// The canonical implementation lives in agent/internal/comparison.CondenseOutput.
430	func CondenseOutput(input, namespacePrefix string) string {
431		var kept []string
432		skippingTokens := false
433		skippingDiff := false
434		blankRun := 0
435		lastWasKept := false
436		keepNextResult := false
437	
438		lines := strings.Split(input, "\n")
439		if len(lines) > 0 && lines[len(lines)-1] == "" {
440			lines = lines[:len(lines)-1]
441		}
442	
443		for _, line := range lines {
444			if strings.HasPrefix(line, "Commands run:") {
445				continue
446			}
447			if line == "tokens used" {
448				skippingTokens = true
449				continue
450			}
451			if skippingTokens {
452				skippingTokens = false
453				continue
454			}
455			if condenseIsDiffHeader(line) {
456				skippingDiff = true
457				continue
458			}
459			if skippingDiff {
460				if condenseIsDiffHeader(line) {
461					continue
462				}
463				if len(line) > 0 && (line[0] == '+' || line[0] == '-' || line[0] == ' ') {
464					continue
465				}
466				skippingDiff = false
467			}
468			if line == "" {
469				blankRun++
470				continue
471			}
472			keep := false
473			if keepNextResult {
474				keep = true
475				keepNextResult = false
476			}
477			if namespacePrefix != "" && strings.HasPrefix(line, namespacePrefix) {
478				keep = true
479			}
480			if strings.HasPrefix(line, "$ ") {
481				keep = true
482				keepNextResult = true
483			}
484			for _, kw := range []string{"error", "Error", "ERROR", "warning", "Warning", "WARN", "FAIL", "fail", "panic"} {
485				if strings.Contains(line, kw) {
486					keep = true
487					break
488				}
489			}
490			for _, kw := range []string{"hx-", "helix-", "FEAT-", "US-", "COMPLETE", "BLOCKED", "CLOSED", "closed", "commit "} {
491				if strings.Contains(line, kw) {
492					keep = true
493					break
494				}
495			}
496			if len(line) > 0 && condenseIsAlphaNumUnderscore(rune(line[0])) && strings.Contains(line, ":") {
497				keep = true
498			}
499			if strings.HasPrefix(line, "#") || strings.HasPrefix(line, "|") || strings.HasPrefix(line, " |") || strings.HasPrefix(line, "**") {
500				keep = true
501			}
502			if strings.HasPrefix(line, "Phase") || strings.HasPrefix(line, "Step") || strings.HasPrefix(line, "---") {
503				keep = true
504			}
505			if keep {
506				if lastWasKept && blankRun > 0 {
507					kept = append(kept, "")
508				}
509				blankRun = 0
510				lastWasKept = true
511				kept = append(kept, line)
512			}
513		}
514	
515		if len(kept) == 0 {
516			return ""
517		}
518		result := strings.Join(kept, "\n")
519		return condenseTrimBlankLines(result)
520	}
521	
522	func condenseIsDiffHeader(line string) bool {
523		return strings.HasPrefix(line, "diff --git ") ||
524			strings.HasPrefix(line, "index ") ||
525			strings.HasPrefix(line, "--- a/") ||
526			strings.HasPrefix(line, "+++ b/") ||
527			strings.HasPrefix(line, "@@ ")
528	}
529	
530	func condenseIsAlphaNumUnderscore(r rune) bool {
531		return (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9') || r == '_'
532	}
533	
534	func condenseTrimBlankLines(s string) string {
535		lines := strings.Split(s, "\n")
536		start := 0
537		for start < len(lines) && strings.TrimSpace(lines[start]) == "" {
538			start++
539		}
540		end := len(lines)
541		for end > start && strings.TrimSpace(lines[end-1]) == "" {
542			end--
543		}
544		return strings.Join(lines[start:end], "\n")
545	}
