547	// LoadBenchmarkSuite reads a benchmark suite from a JSON file.
548	// The canonical implementation lives in agent/internal/comparison.
549	func LoadBenchmarkSuite(path string) (*BenchmarkSuite, error) {
550		data, err := os.ReadFile(path)
551		if err != nil {
552			return nil, fmt.Errorf("reading benchmark suite: %w", err)
553		}
554		var suite BenchmarkSuite
555		if err := json.Unmarshal(data, &suite); err != nil {
556			return nil, fmt.Errorf("parsing benchmark suite: %w", err)
557		}
558		return &suite, nil
559	}
